#!/usr/bin/env bash
# install-git-hooks.sh — one-time setup.
# Installs the pre-commit hook that runs scripts/pre-commit-check.sh.
#
# Run once after cloning the repo:
#
#   bash scripts/install-git-hooks.sh
#
# Idempotent: safe to re-run. If a pre-commit hook already exists
# that doesn't call pre-commit-check.sh, the script aborts and asks
# you to merge manually.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_DIR="$(dirname "$SCRIPT_DIR")"
HOOK_PATH="$REPO_DIR/.git/hooks/pre-commit"

if [ ! -d "$REPO_DIR/.git" ]; then
  echo "error: $REPO_DIR is not a git repository (no .git/ directory)"
  exit 1
fi

mkdir -p "$(dirname "$HOOK_PATH")"

if [ -f "$HOOK_PATH" ]; then
  if grep -q "pre-commit-check.sh" "$HOOK_PATH"; then
    echo "pre-commit hook already wired to pre-commit-check.sh; nothing to do."
    exit 0
  fi
  echo "error: a pre-commit hook already exists at $HOOK_PATH and does not call pre-commit-check.sh"
  echo "       merge manually — add:  bash \"\$(git rev-parse --show-toplevel)/scripts/pre-commit-check.sh\""
  exit 1
fi

cat > "$HOOK_PATH" <<'EOF'
#!/usr/bin/env bash
# Auto-generated by scripts/install-git-hooks.sh — edits will be overwritten if re-run.
set -euo pipefail
exec bash "$(git rev-parse --show-toplevel)/scripts/pre-commit-check.sh"
EOF

chmod +x "$HOOK_PATH"
echo "✓ installed pre-commit hook at $HOOK_PATH"
echo "  it will run on every 'git commit' and call scripts/pre-commit-check.sh"
